def _micro_strategy_column_to_nested(
    micro_strategy_column: MicroStrategyColumn,
) -> MicroStrategyColumnNested:
    """Convert flat MicroStrategyColumn to nested format."""
    attrs = MicroStrategyColumnAttributes()
    _populate_micro_strategy_column_attrs(attrs, micro_strategy_column)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        micro_strategy_column,
        _MICRO_STRATEGY_COLUMN_REL_FIELDS,
        MicroStrategyColumnRelationshipAttributes,
    )
    return MicroStrategyColumnNested(
        guid=micro_strategy_column.guid,
        type_name=micro_strategy_column.type_name,
        status=micro_strategy_column.status,
        version=micro_strategy_column.version,
        create_time=micro_strategy_column.create_time,
        update_time=micro_strategy_column.update_time,
        created_by=micro_strategy_column.created_by,
        updated_by=micro_strategy_column.updated_by,
        classifications=micro_strategy_column.classifications,
        classification_names=micro_strategy_column.classification_names,
        meanings=micro_strategy_column.meanings,
        labels=micro_strategy_column.labels,
        business_attributes=micro_strategy_column.business_attributes,
        custom_attributes=micro_strategy_column.custom_attributes,
        pending_tasks=micro_strategy_column.pending_tasks,
        proxy=micro_strategy_column.proxy,
        is_incomplete=micro_strategy_column.is_incomplete,
        provenance_type=micro_strategy_column.provenance_type,
        home_id=micro_strategy_column.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _micro_strategy_column_from_nested(
    nested: MicroStrategyColumnNested,
) -> MicroStrategyColumn:
    """Convert nested format to flat MicroStrategyColumn."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else MicroStrategyColumnAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _MICRO_STRATEGY_COLUMN_REL_FIELDS,
        MicroStrategyColumnRelationshipAttributes,
    )
    return MicroStrategyColumn(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_micro_strategy_column_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _micro_strategy_column_to_nested_bytes(
    micro_strategy_column: MicroStrategyColumn, serde: Serde
) -> bytes:
    """Convert flat MicroStrategyColumn to nested JSON bytes."""
    return serde.encode(_micro_strategy_column_to_nested(micro_strategy_column))


def _micro_strategy_column_from_nested_bytes(
    data: bytes, serde: Serde
) -> MicroStrategyColumn:
    """Convert nested JSON bytes to flat MicroStrategyColumn."""
    nested = serde.decode(data, MicroStrategyColumnNested)
    return _micro_strategy_column_from_nested(nested)


